def fib(n):
    if n < 0:
        raise ValueError("n must be non-negative")
    def helper(k):
        if k == 0:
            return (0, 1)
        a, b = helper(k // 2)
        c = a * (2 * b - a)
        d = a * a + b * b
        if k % 2 == 0:
            return (c, d)
        else:
            return (d, c + d)
    return helper(n)[1]
```

The bug is that the function returns `helper(n)[0]` (which is F(n)) but the fast doubling convention used here returns (F(k), F(k+1)) from helper(k), so the n-th Fibonacci number is the second element, not the first. The fix is to return `helper(n)[1]`.

import heapq

def dijkstra(graph, start, end):
    queue = []
    heapq.heappush(queue, (0, start))
    distances = {start: 0}
    visited = set()

    while queue:
        dist, current = heapq.heappop(queue)

        if current == end:
            return dist

        if current in visited:
            continue
        visited.add(current)

        for neighbor, weight in graph.get(current, {}).items():
            old_dist = distances.get(neighbor, float('inf'))
            new_dist = dist + weight
            if new_dist < old_dist:
                distances[neighbor] = new_dist
                heapq.heappush(queue, (new_dist, neighbor))

    return distances.get(end, float('inf'))

import threading
import heapq

class ClosedQueueError(Exception):
    pass

class ThreadSafePriorityQueue:
    def __init__(self, max_size: int):
        self.max_size = max_size
        self.queue = []
        self.lock = threading.Lock()
        self.not_empty = threading.Condition(self.lock)
        self.not_full = threading.Condition(self.lock)
        self.closed = False

    def put(self, priority: int, item) -> None:
        with self.lock:
            while len(self.queue) >= self.max_size:
                if self.closed:
                    raise ClosedQueueError("Queue is closed")
                self.not_full.wait()
            if self.closed:
                raise ClosedQueueError("Queue is closed")
            heapq.heappush(self.queue, (priority, item))
            self.not_empty.notify()

    def get(self):
        with self.lock:
            while len(self.queue) == 0:
                if self.closed:
                    raise ClosedQueueError("Queue is closed")
                self.not_empty.wait()
            priority, item = heapq.heappop(self.queue)
            self.not_full.notify()
            return item

    def close(self) -> None:
        with self.lock:
            self.closed = True
            self.not_empty.notify_all()
            self.not_full.notify_all()

