    return "".join(res)

def max_k_subarray(arr, k):
    if len(arr) < k:
        return (0, -1)
    if k <= 0:
        return (0, -1)

    window_sum = sum(arr[:k])
    max_sum = window_sum
    max_index = 0

    for i in range(k, len(arr)):
        window_sum += arr[i] - arr[i - k]
        if window_sum > max_sum:
            max_sum = window_sum
            max_index = i - k + 1

    return (max_sum, max_index)

