def transform_matrix(matrix: list[list[int]]) -> list[list[int]]:
    if not matrix or not matrix[0]:
        return []
    rows = len(matrix)
    cols = len(matrix[0])
    temp = [[0] * cols for _ in range(rows)]
    for r in range(rows):
        for c in range(cols):
            val = matrix[r][c]
            if val % 2 == 1:
                temp[r][c] = val * 2
            else:
                temp[r][c] = val // 2
    transposed = [[0] * rows for _ in range(cols)]
    for r in range(rows):
        for c in range(cols):
            transposed[c][r] = temp[r][c]
    for r in range(cols):
        transposed[r] = transposed[r][::-1]
    return transposed

