def find_lexicographical_shortest_path(edges: list[list[str]], start: str, end: str) -> list[str]:
    import collections

    def is_valid(n: str) -> bool:
        return bool(n) and all(c.isalnum() or c == '_' for c in n)

    if not is_valid(start) or not is_valid(end):
        return []

    adj = collections.defaultdict(set)
    for edge in edges:
        if len(edge) != 2:
            continue
        u, v = edge
        if is_valid(u) and is_valid(v):
            adj[u].add(v)

    if start == end:
        return [start]

    queue = collections.deque([(start, [start])])
    visited = {start: 0}
    shortest_paths = []
    min_len = float('inf')

    while queue:
        curr, path = queue.popleft()

        if len(path) > min_len:
            continue

        if curr == end:
            if len(path) < min_len:
                shortest_paths = [path]
                min_len = len(path)
            elif len(path) == min_len:
                shortest_paths.append(path)
            continue

        for neighbor in sorted(adj[curr]):
            if neighbor not in visited or visited[neighbor] == len(path):
                visited[neighbor] = len(path)
                queue.append((neighbor, path + [neighbor]))

    if not shortest_paths:
        return []
    return min(shortest_paths)

def rle_encode_conditional(s: str) -> list[tuple[str, int]]:
    result = []
    current_char = None
    current_count = 0

    for char in s:
        if char.isspace():
            continue
        if char.isdigit():
            if current_char is not None:
                result.append((current_char, current_count))
                current_char = None
                current_count = 0
            result.append((char, 1))
        else:
            lower_char = char.lower()
            if current_char is None:
                current_char = lower_char
                current_count = 1
            elif lower_char == current_char:
                current_count += 1
            else:
                result.append((current_char, current_count))
                current_char = lower_char
                current_count = 1

    if current_char is not None:
        result.append((current_char, current_count))

    return result

