    def is_vowel(c: str) -> bool:
        return c.lower() in 'aeiou'

    def is_consonant(c: str) -> bool:
        return c.isalpha() and not is_vowel(c)

    n = len(s)
    best_sub = ""

    for i in range(n):
        if not is_consonant(s[i]):
            continue
        vowels_seen = set()
        for j in range(i, n):
            char = s[j]
            if is_vowel(char):
                vowels_seen.add(char.lower())
            if len(vowels_seen) > k:
