def resumen_texto_seguro(texto, max_caracteres, umbral_palabra):
    """Devuelve un resumen de palabras completas del texto respetando max_caracteres y un umbral de longitud relativa."""
    if not texto or max_caracteres <= 0:
        return ""
    if len(texto) <= max_caracteres:
        return texto
    palabras = texto.split()
    if not palabras:
        return ""
    longitud_promedio_palabra = len(texto) / len(palabras)
    umbral_absoluto = umbral_palabra * longitud_promedio_palabra
    resultado = []
    longitud_actual = 0
    for palabra in palabras:
        if len(palabra) < umbral_absoluto:
            continue
        if not resultado:
            if len(palabra) > max_caracteres:
                return ""
            resultado.append(palabra)
            longitud_actual = len(palabra)
        else:
            if longitud_actual + 1 + len(palabra) > max_caracteres:
                break
            resultado.append(palabra)
            longitud_actual += 1 + len(palabra)
    return " ".join(resultado)

def expand_repeat_shorthand(s: str) -> str:
    stack = []
    i = 0
    n = len(s)

    while i < n:
        char = s[i]
        if char == ']':
            temp = []
            while stack and stack[-1] != '[':
                temp.append(stack.pop())
            if not stack:
                return None
            stack.pop() 

            inner = "".join(reversed(temp))
            if ':' not in inner:
                return None
            parts = inner.split(':', 1)
            count_str, pattern = parts[0], parts[1]
            if not count_str.isdigit():
                return None
            count = int(count_str)
            if count <= 0:
                return None

            stack.append(pattern * count)
            i += 1
        elif char == '[':
            stack.append('[')
            i += 1
        else:
            stack.append(char)
            i += 1

    if '[' in stack:
        return None

    return "".join(stack)

