def compress_binary_matrix(matrix: list[list[int]]) -> str:
    if not matrix or not isinstance(matrix, list):
        return None
    n = len(matrix)
    if n == 0:
        return None
    if any(not isinstance(row, list) or len(row) != n for row in matrix):
        return None
    if (n & (n - 1)) != 0:
        return None

    for r in range(n):
        for c in range(n):
            if matrix[r][c] not in (0, 1):
                return None

    def compress(r_start: int, r_end: int, c_start: int, c_end: int) -> str:
        first = matrix[r_start][c_start]
        all_same = True
        for r in range(r_start, r_end):
            for c in range(c_start, c_end):
                if matrix[r][c] != first:
                    all_same = False
                    break
            if not all_same:
                break
        if all_same:
            return str(first)

        r_mid = (r_start + r_end) // 2
        c_mid = (c_start + c_end) // 2
        tl = compress(r_start, r_mid, c_start, c_mid)
        tr = compress(r_start, r_mid, c_mid, c_end)
        bl = compress(r_mid, r_end, c_start, c_mid)
        br = compress(r_mid, r_end, c_mid, c_end)
        return f"X{tl}{tr}{bl}{br}"

    return compress(0, n, 0, n)

