import zlib


def decode_packet(payload: bytes) -> dict:
    if len(payload) < 12:
        raise ValueError("bad magic")
    if payload[0] != 0x5A or payload[1] != 0xA5:
        raise ValueError("bad magic")

    version_type = payload[2]
    version = version_type >> 4
    pkt_type = version_type & 0x0F
    if version != 1:
        raise ValueError("bad version")
    if pkt_type != 2:
        raise ValueError("bad type")

    flags = payload[3]
    if flags & ~0x03:
        raise ValueError("bad flags")
    little_endian = bool(flags & 0x01)
    has_timestamp = bool(flags & 0x02)

    sample_count = struct.unpack(">I", payload[4:8])[0]
    if sample_count == 0 or sample_count > 1024:
        raise ValueError("bad count")

    stored_crc = struct.unpack(">I", payload[8:12])[0]
    body = payload[12:]
    if zlib.crc32(body) & 0xFFFFFFFF != stored_crc:
        raise ValueError("bad crc")

    offset = 0
    timestamp_ms = None
    if has_timestamp:
        if len(body) < 8:
            raise ValueError("bad crc")
        timestamp_ms = struct.unpack(">Q", body[offset:offset + 8])[0]
        offset += 8

    sample_fmt = "<h" if little_endian else ">h"
    expected_len = 2 * sample_count
    if len(body) - offset < expected_len:
        raise ValueError("bad crc")
    samples = list(struct.unpack_from(f"{sample_fmt[:-1]}{sample_count}h", body, offset))

    return {
        "version": version,
        "type": pkt_type,
        "flags": {
            "little_endian": little_endian,
            "has_timestamp": has_timestamp,
        },
        "sample_count": sample_count,
        "timestamp_ms": timestamp_ms,
