    }

def parse_cron_expression(cron_str: str) -> dict[str, list[int]]:
    def parse_cron_field(field: str, min_val: int, max_val: int) -> list[int]:
        allowed = set()
        parts = field.split(',')

        for part in parts:
            if not part:
                return None

            if '/' in part:
                subparts = part.split('/')
                if len(subparts) != 2:
                    return None
                range_part, step_str = subparts
                if not step_str.isdigit():
                    return None
                step = int(step_str)
                if step <= 0:
                    return None

                if range_part == '*':
                    start, end = min_val, max_val
                elif '-' in range_part:
                    r_parts = range_part.split('-')
                    if len(r_parts) != 2 or not r_parts[0].isdigit() or not r_parts[1].isdigit():
                        return None
                    start, end = int(r_parts[0]), int(r_parts[1])
                elif range_part.isdigit():
                    start = int(range_part)
                    end = max_val
                else:
                    return None
            else:
                step = 1
                if part == '*':
                    start, end = min_val, max_val
                elif '-' in part:
                    r_parts = part.split('-')
                    if len(r_parts) != 2 or not r_parts[0].isdigit() or not r_parts[1].isdigit():
                        return None
                    start, end = int(r_parts[0]), int(r_parts[1])
                elif part.isdigit():
                    start = end = int(part)
                else:
                    return None

            if not (min_val <= start <= max_val) or not (min_val <= end <= max_val) or start > end:
                return None

            for v in range(start, end + 1, step):
                allowed.add(v)

        return sorted(list(allowed))

    fields = cron_str.split()
    if len(fields) != 5:
        return None

    field_configs = [
        ("minute", 0, 59),
        ("hour", 0, 23),
        ("day_of_month", 1, 31),
        ("month", 1, 12),
        ("day_of_week", 0, 6)
    ]

    result = {}
    for (name, min_val, max_val), field_str in zip(field_configs, fields):
        parsed = parse_cron_field(field_str, min_val, max_val)
        if parsed is None or not parsed:
            return None
        result[name] = parsed

    return result

def decode_packet_stream(raw_bytes, schema):
    import struct
    from collections import OrderedDict

    TYPE_SIZES = {
        'u8': ('B', 1), 'i8': ('b', 1),
        'u16': ('H', 2), 'i16': ('h', 2),
        'u32': ('I', 4), 'i32': ('i', 4),
        'f32': ('f', 4), 'f64': ('d', 8),
        'bool': ('B', 1),
    }

    def payload_size_for_schema(sch):
        total = 0
        for field in sch:
            t = field['type']
            if t == 'string':
                total += 1
            elif t in TYPE_SIZES:
                total += TYPE_SIZES[t][1]
            else:
                raise ValueError(f"unknown type {t}")
        return total

    expected_payload_size = payload_size_for_schema(schema)

    def decode_field(data, offset, ftype):
        if ftype == 'bool':
            return bool(data[offset]), offset + 1
        if ftype == 'string':
            slen = data[offset]
            if offset + 1 + slen > len(data):
                raise ValueError("string overflow")
            return data[offset + 1:offset + 1 + slen].decode('utf-8'), offset + 1 + slen
        fmt, size = TYPE_SIZES[ftype]
        val = struct.unpack('<' + fmt, data[offset:offset + size])[0]
        return val, offset + size

    packets = []
    pos = 0
    n = len(raw_bytes)

    while pos < n:
        if n - pos < 2:
            break
        pkt_len = struct.unpack('<H', raw_bytes[pos:pos + 2])[0]
        if pkt_len < 3:
            raise ValueError("packet length too small")
        end = pos + pkt_len
        if end > n:
            break
        pkt_type = raw_bytes[pos + 2]
        payload = raw_bytes[pos + 3:end]
        if len(payload) != expected_payload_size:
            raise ValueError("schema mismatch")
        fields = OrderedDict()
        off = 0
        for field in schema:
            name = field['name']
            ftype = field['type']
            val, off = decode_field(payload, off, ftype)
            fields[name] = val
        packets.append({'type': pkt_type, 'fields': fields})
        pos = end
        # align to 4-byte boundary
        if pos % 4 != 0:
            pos += 4 - (pos % 4)
            if pos > n:
                pos = n

    return packets

def normalize_url(url: str) -> str:
    url_lower = url.lower()
    if url_lower.startswith("http://"):
        scheme = "http://"
        rest = url[7:]
    elif url_lower.startswith("https://"):
        scheme = "https://"
        rest = url[8:]
    else:
        return None

    parts = rest.split('/', 1)
    host_part = parts[0]
    path_part = "/" + parts[1] if len(parts) > 1 else ""

    if not host_part:
        return None

    if ':' in host_part:
        host_sub = host_part.split(':')
        if len(host_sub) != 2:
            return None
        domain, port_str = host_sub
        if not port_str.isdigit():
            return None
        port = int(port_str)
        if not (1 <= port <= 65535):
            return None
    else:
        domain = host_part
        port = None

    if not domain:
        return None

    domain = domain.lower()

    port_part = ""
    if port is not None:
        if scheme == "http://" and port == 80:
            pass
        elif scheme == "https://" and port == 443:
            pass
        else:
            port_part = f":{port}"

    if path_part:
        segments = path_part.split('/')
        resolved = []
        for seg in segments:
            if seg == '.' or seg == '':
                continue
            elif seg == '..':
                if resolved:
                    resolved.pop()
            else:
                resolved.append(seg)
        ends_with_slash = path_part.endswith('/') or path_part.endswith('/.') or path_part.endswith('/..')
        path_str = "/" + "/".join(resolved)
        if ends_with_slash and not path_str.endswith('/') and path_str != '/':
            path_str += '/'
    else:
        path_str = ""

    return f"{scheme}{domain}{port_part}{path_str}"

def romano_para_inteiro(romano: str) -> int:
    if not romano or not isinstance(romano, str):
        return None

    val = {'I': 1, 'V': 5, 'X': 10, 'L': 50, 'C': 100, 'D': 500, 'M': 1000}

    if not all(c in val for c in romano):
        return None

    for c in ['I', 'X', 'C', 'M']:
        if c * 4 in romano:
            return None
    for c in ['V', 'L', 'D']:
        if c * 2 in romano:
            return None

    n = len(romano)
    nums = [val[c] for c in romano]
    total = 0
    i = 0
    last_subtracted = 0
    last_val = float('inf')

    while i < n:
        curr = nums[i]
        if i + 1 < n and nums[i] < nums[i+1]:
            nxt = nums[i+1]
            if curr == 1 and nxt not in (5, 10):
                return None
            elif curr == 10 and nxt not in (50, 100):
                return None
            elif curr == 100 and nxt not in (500, 1000):
                return None
            elif curr in (5, 50, 500):
                return None

            val_pair = nxt - curr
            if val_pair >= last_val:
                return None

            total += val_pair
            last_val = val_pair
            last_subtracted = curr
            i += 2
        else: 
            if curr > last_val:
                return None
            if last_subtracted > 0 and curr >= last_subtracted:
                return None

            total += curr
            last_val = curr
            last_subtracted = 0
            i += 1

    return total

