def resumen_estadistico_seguro(datos, opciones=None):
    if not isinstance(datos, list) or not isinstance(opciones, dict) if opciones is not None else False:
        return None
    if opciones is None:
        opciones = {}
    redondeo = opciones.get("redondeo", None)
    ignorar_nan = opciones.get("ignorar_nan", True)
    if redondeo is not None and (not isinstance(redondeo, int) or redondeo < 0):
        return None
    if not isinstance(ignorar_nan, bool):
        return None

    valores = []
    for x in datos:
        if isinstance(x, (int, float)) and not isinstance(x, bool):
            valores.append(float(x))
        elif not ignorar_nan:
            return None

    if len(valores) == 0:
        return None

    n = len(valores)
    media = sum(valores) / n
    valores_ordenados = sorted(valores)
    if n % 2 == 1:
        mediana = valores_ordenados[n // 2]
    else:
        mediana = (valores_ordenados[n // 2 - 1] + valores_ordenados[n // 2]) / 2

    frecuencias = {}
    for v in valores:
        frecuencias[v] = frecuencias.get(v, 0) + 1
    max_freq = max(frecuencias.values())
    if max_freq == 1:
        moda = []
    else:
        moda = sorted([v for v, f in frecuencias.items() if f == max_freq])

    varianza = sum((x - media) ** 2 for x in valores) / n
    desviacion = varianza ** 0.5
    rango = max(valores) - min(valores)

    def redondear(v):
        if redondeo is None:
            return v
        return round(v, redondeo)

    resultado = {
        "media": redondear(media),
        "mediana": redondear(mediana),
        "moda": [redondear(m) for m in moda],
        "desviacion": redondear(desviacion),
        "rango": redondear(rango),
        "validos": n,
    }
    return resultado
